{
  "observation_id": "obs_status_tb_interest_2015",
  "obs_type": "status",
  "summary": "In early 2015 and again in June 2015, Thoma Bravo informally approached the Company and expressed interest in a possible business transaction without making a specific proposal."
}
{
  "observation_id": "obs_status_tb_interest_201601",
  "obs_type": "status",
  "summary": "In January 2016, Thoma Bravo reiterated its interest in a potential transaction and made no specific proposal."
}
{
  "observation_id": "obs_proposal_tb_20160309",
  "obs_type": "proposal",
  "summary": "Thoma Bravo sent the Board an unsolicited, non-binding indication of interest to acquire the Company for $15.00 per share in cash."
}
{
  "observation_id": "obs_process_board_evaluation_20160310",
  "obs_type": "process",
  "summary": "The Board began evaluating Thoma Bravo's indication of interest and authorized an advisory committee to recommend a financial advisor."
}
{
  "observation_id": "obs_process_advisor_engagement_committee_20160314_20160324",
  "obs_type": "process",
  "summary": "The advisory committee met on March 14 and March 24, 2016 to consider engaging a financial advisor and authorized management to inquire whether Barclays would be available to act for the Company in connection with a potential strategic transaction."
}
{
  "observation_id": "obs_process_barclays_retained_20160415",
  "obs_type": "process",
  "summary": "The Board engaged Barclays as the Company's financial advisor."
}
{
  "observation_id": "obs_agreement_barclays_engagement_letter_20160419",
  "obs_type": "agreement",
  "summary": "The Company countersigned Barclays' engagement letter, dated April 15, 2016, as authorized during the April 15, 2016 Board meeting."
}
{
  "observation_id": "obs_process_sale_launch_20160505",
  "obs_type": "process",
  "summary": "The Board decided to further explore a potential business combination transaction and approved confidential outreach to the indicative list of parties."
}
{
  "observation_id": "obs_agreement_financial_sponsor_cohort_nda_20160506_20160609",
  "obs_type": "agreement",
  "summary": "During the May 6 through June 9, 2016 outreach period, four financial sponsors executed confidentiality agreements with the Company, including Thoma Bravo on May 10, 2016."
}
{
  "observation_id": "obs_agreement_ndas_20160506_20160609",
  "obs_type": "agreement",
  "summary": "Three strategic parties and four financial sponsors executed confidentiality agreements with the Company during the strategic process."
}
{
  "observation_id": "obs_solicitation_ioi_20160603",
  "obs_type": "solicitation",
  "summary": "Barclays sent bid instruction letters on behalf of the Company to six parties requesting indications of interest by June 9, 2016."
}
{
  "observation_id": "obs_status_strategic_1_not_interested_20160608",
  "obs_type": "status",
  "summary": "Strategic 1 said it was no longer interested in the strategic process and would not submit an indication of interest."
}
{
  "observation_id": "obs_agreement_strategic_3_nda_by_20160609",
  "obs_type": "agreement",
  "summary": "By the June 9, 2016 deadline, Strategic 3 had executed a confidentiality agreement with the Company and met with management."
}
{
  "observation_id": "obs_proposal_sponsor_a_20160609",
  "obs_type": "proposal",
  "summary": "Sponsor A submitted a written preliminary non-binding indication of interest at $16.50 per share."
}
{
  "observation_id": "obs_proposal_sponsor_b_20160609",
  "obs_type": "proposal",
  "summary": "Sponsor B submitted a written preliminary non-binding indication of interest at $17.00 to $18.00 per share."
}
{
  "observation_id": "obs_proposal_tb_20160609",
  "obs_type": "proposal",
  "summary": "Thoma Bravo submitted a written preliminary non-binding indication of interest at $17.25 per share and provided a draft merger agreement."
}
{
  "observation_id": "obs_status_selected_to_advance_20160612",
  "obs_type": "status",
  "summary": "The Board advanced Sponsor A, Sponsor B, and Thoma Bravo to the second phase of the strategic process."
}
{
  "observation_id": "obs_status_strategic_2_not_interested_20160612",
  "obs_type": "status",
  "summary": "Strategic 2 said it was no longer interested in exploring a potential transaction."
}
{
  "observation_id": "obs_status_strategic_3_not_interested_20160614",
  "obs_type": "status",
  "summary": "Strategic 3 said it was no longer interested in exploring a potential transaction."
}
{
  "observation_id": "obs_status_sponsor_a_cannot_improve_20160615",
  "obs_type": "status",
  "summary": "Sponsor A said any second-round bid would not be meaningfully higher than its June 9 indication of interest."
}
{
  "observation_id": "obs_process_special_committee_20160617",
  "obs_type": "process",
  "summary": "The Board formed the Special Committee to oversee the strategic process."
}
{
  "observation_id": "obs_status_sponsor_a_excluded_20160617",
  "obs_type": "status",
  "summary": "The Special Committee said it was not interested in pursuing Sponsor A at its initial-bid price."
}
{
  "observation_id": "obs_status_strategic_4_not_interested_20160623",
  "obs_type": "status",
  "summary": "Strategic 4 said an acquisition of the Company was not a strategic fit and that it was not interested in participating in the strategic process."
}
{
  "observation_id": "obs_solicitation_final_bid_20160624",
  "obs_type": "solicitation",
  "summary": "Barclays sent final bid process letters to Sponsor B and Thoma Bravo requesting marked drafts and setting a July 8 final bid deadline."
}
{
  "observation_id": "obs_status_sponsor_b_cannot_improve_20160629",
  "obs_type": "status",
  "summary": "Sponsor B said any final bid would be significantly below its June 9 indication of interest."
}
{
  "observation_id": "obs_status_sponsor_b_excluded_20160630",
  "obs_type": "status",
  "summary": "The Special Committee decided not to pursue Sponsor B at a price significantly below its original indication."
}
{
  "observation_id": "obs_proposal_tb_markup_20160707",
  "obs_type": "proposal",
  "summary": "Thoma Bravo, through Kirkland, sent a revised draft of the merger agreement to Goodwin."
}
{
  "observation_id": "obs_proposal_tb_20160708",
  "obs_type": "proposal",
  "summary": "Thoma Bravo submitted the only final bid at $19.00 per share in cash and said it was prepared to execute its revised draft merger agreement."
}
{
  "observation_id": "obs_proposal_tb_20160709",
  "obs_type": "proposal",
  "summary": "Thoma Bravo submitted a revised written non-binding best-and-final proposal at $19.25 per share."
}
{
  "observation_id": "obs_solicitation_tb_best_final_20160709",
  "obs_type": "solicitation",
  "summary": "Barclays informed Thoma Bravo that it should submit its best and final offer."
}
{
  "observation_id": "obs_agreement_exclusivity_20160711",
  "obs_type": "agreement",
  "summary": "Kirkland sent Goodwin a draft exclusivity agreement, but the Company declined to enter into it."
}
{
  "observation_id": "obs_process_board_approval_20160712",
  "obs_type": "process",
  "summary": "The Board approved the merger agreement with Thoma Bravo and recommended stockholder approval."
}
{
  "observation_id": "obs_process_special_committee_recommendation_20160712",
  "obs_type": "process",
  "summary": "The Special Committee unanimously recommended that the Board enter into the merger agreement with Thoma Bravo."
}
{
  "observation_id": "obs_agreement_merger_agreement_20160713",
  "obs_type": "agreement",
  "summary": "The parties finalized and executed the merger agreement."
}
{
  "observation_id": "obs_outcome_executed_20160713",
  "obs_type": "outcome",
  "summary": "The parties executed the merger agreement."
}
{
  "observation_id": "obs_process_press_release_20160713",
  "obs_type": "process",
  "summary": "The Company and Thoma Bravo issued a joint press release announcing execution of the merger agreement."
}

